css:
* {
  box-sizing: border-box !important;
}

html, body {
  min-height: 100vh !important;
  background: #0a0514 !important;
  color: #c0b8d0 !important;
  font-family: 'Segoe UI', 'Arial', system-ui, sans-serif !important;
}

body::before {
  content: '' !important;
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  width: 100% !important;
  height: 100% !important;
  z-index: -1 !important;
  background: 
    radial-gradient(circle at 30% 20%, rgba(120,40,180,0.25) 0%, transparent 60%),
    radial-gradient(circle at 80% 70%, rgba(255,20,100,0.15) 0%, transparent 50%),
    radial-gradient(circle at 50% 50%, rgba(10,5,20,0.9) 0%, #0a0514 100%);
  animation: bgShift 25s ease-in-out infinite alternate !important;
}

@keyframes bgShift {
  0% { background-position: 0% 0%; }
  100% { background-position: 100% 100%; }
}

body::after {
  content: '' !important;
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  width: 100% !important;
  height: 100% !important;
  z-index: -1 !important;
  pointer-events: none !important;
  background: 
    repeating-linear-gradient(0deg, rgba(255,0,200,0.04) 0px, rgba(255,0,200,0.04) 1px, transparent 1px, transparent 4px),
    repeating-linear-gradient(90deg, rgba(0,200,255,0.04) 0px, rgba(0,200,255,0.04) 1px, transparent 1px, transparent 4px);
  animation: gridMove 30s linear infinite !important;
}

@keyframes gridMove {
  0% { transform: translate(0, 0); }
  100% { transform: translate(20px, 10px); }
}

.p-pageWrapper,
.p-body,
.p-body-inner,
.p-body-main,
.p-body-content,
.p-body-pageContent,
.p-body-header,
.pageContent,
.p-body-inner {
  background: transparent !important;
}

.p-body-inner {
  background: rgba(12, 6, 24, 0.8) !important;
  backdrop-filter: blur(8px) !important;
  -webkit-backdrop-filter: blur(8px) !important;
  border-radius: 28px !important;
  padding: 24px !important;
  box-shadow: 0 0 60px rgba(200,0,255,0.1), inset 0 0 60px rgba(100,0,200,0.05) !important;
  border: 1px solid rgba(255,0,200,0.15) !important;
  margin: 16px auto !important;
  position: relative;
  overflow: hidden;
}

.p-body-inner::before {
  content: '' !important;
  position: absolute !important;
  top: -2px !important;
  left: -2px !important;
  right: -2px !important;
  bottom: -2px !important;
  border-radius: 30px !important;
  background: linear-gradient(45deg, rgba(255,0,200,0.2), rgba(0,200,255,0.2), rgba(255,255,0,0.2)) !important;
  background-size: 300% 300% !important;
  z-index: -1 !important;
  animation: borderGlow 6s ease-in-out infinite alternate !important;
}

@keyframes borderGlow {
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}

.p-header {
  background: rgba(16, 8, 32, 0.7) !important;
  backdrop-filter: blur(8px) !important;
  border-bottom: 1px solid rgba(255,0,200,0.15) !important;
  border-radius: 28px 28px 0 0 !important;
  padding: 12px 24px !important;
  box-shadow: 0 0 30px rgba(200,0,255,0.05) !important;
}

.p-header-logo a {
  color: #f0a0ff !important;
  font-weight: 700 !important;
  letter-spacing: -0.5px !important;
  text-shadow: 0 0 20px rgba(200,0,255,0.3) !important;
}

.p-header-logo a:hover {
  text-shadow: 0 0 40px rgba(255,0,200,0.5) !important;
}

.p-nav {
  background: rgba(12, 6, 24, 0.8) !important;
  backdrop-filter: blur(8px) !important;
  border-bottom: 1px solid rgba(255,0,200,0.1) !important;
  box-shadow: 0 4px 30px rgba(0,0,0,0.6) !important;
  padding: 0 16px !important;
}

.p-nav-inner {
  background: transparent !important;
}

.p-nav-list {
  display: flex !important;
  gap: 4px !important;
  background: transparent !important;
}

.p-nav-list .p-navEl {
  color: #b0a0c0 !important;
  font-weight: 500 !important;
  padding: 12px 20px !important;
  border-radius: 40px !important;
  transition: all 0.25s ease !important;
  background: transparent !important;
  text-shadow: 0 0 10px rgba(0,0,0,0.5) !important;
}

.p-nav-list .p-navEl:hover {
  background: rgba(255,0,200,0.15) !important;
  color: #f0c0ff !important;
  transform: translateY(-2px) !important;
  box-shadow: 0 0 30px rgba(200,0,255,0.15) !important;
  text-shadow: 0 0 20px rgba(255,0,200,0.3) !important;
}

.p-nav-list .p-navEl.is-selected {
  background: rgba(255,0,200,0.15) !important;
  color: #f0c0ff !important;
  box-shadow: 0 0 30px rgba(200,0,255,0.1), inset 0 0 0 1px rgba(255,0,200,0.2) !important;
  text-shadow: 0 0 20px rgba(255,0,200,0.3) !important;
}

.p-nav-opposite {
  background: transparent !important;
}

.p-navgroup {
  background: transparent !important;
}

.p-navgroup-link {
  color: #b0a0c0 !important;
  transition: all 0.2s !important;
}

.p-navgroup-link:hover {
  color: #f0c0ff !important;
  background: rgba(255,0,200,0.1) !important;
  border-radius: 40px !important;
  text-shadow: 0 0 20px rgba(255,0,200,0.2) !important;
}

.block {
  background: rgba(16, 8, 32, 0.4) !important;
  backdrop-filter: blur(6px) !important;
  -webkit-backdrop-filter: blur(6px) !important;
  border-radius: 28px !important;
  border: 1px solid rgba(255,0,200,0.08) !important;
  box-shadow: 0 4px 30px rgba(0,0,0,0.5), inset 0 0 30px rgba(200,0,255,0.03) !important;
  padding: 20px !important;
  margin-bottom: 24px !important;
  transition: all 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94) !important;
  position: relative;
  overflow: hidden;
}

.block:hover {
  box-shadow: 0 8px 50px rgba(200,0,255,0.15), inset 0 0 30px rgba(200,0,255,0.05) !important;
  transform: translateY(-2px) !important;
  border-color: rgba(255,0,200,0.2) !important;
}

.block-container {
  background: transparent !important;
  border: none !important;
}

.block-body {
  background: transparent !important;
}

.block-minorHeader {
  color: #d0b0e0 !important;
  font-weight: 600 !important;
  padding: 12px 16px !important;
  border-bottom: 1px solid rgba(255,0,200,0.08) !important;
  text-shadow: 0 0 20px rgba(200,0,255,0.1) !important;
}

.node {
  background: rgba(20, 10, 40, 0.4) !important;
  border-radius: 24px !important;
  border: 1px solid rgba(255,0,200,0.06) !important;
  padding: 16px 20px !important;
  margin-bottom: 8px !important;
  transition: all 0.3s ease !important;
}

.node:hover {
  background: rgba(30, 15, 60, 0.5) !important;
  border-color: rgba(255,0,200,0.15) !important;
  transform: translateY(-2px) !important;
  box-shadow: 0 8px 30px rgba(200,0,255,0.08) !important;
}

.node-title a {
  color: #d0b0e0 !important;
  font-weight: 600 !important;
  text-shadow: 0 0 10px rgba(200,0,255,0.05) !important;
}

.node-title a:hover {
  color: #f0c0ff !important;
  text-shadow: 0 0 30px rgba(255,0,200,0.2) !important;
}

.node-stats {
  color: #9080a0 !important;
}

.node-extra {
  color: #9080a0 !important;
}

.node-extra-title {
  color: #b0a0c0 !important;
}

.node-extra-title:hover {
  color: #d0b0e0 !important;
}

.uix_newIndicator {
  background: rgba(255,0,200,0.15) !important;
  color: #f080ff !important;
  border-radius: 40px !important;
  padding: 2px 12px !important;
  font-size: 11px !important;
  text-shadow: 0 0 10px rgba(255,0,200,0.2) !important;
}

.node-body {
  background: transparent !important;
  display: flex !important;
  align-items: center !important;
  flex-wrap: wrap !important;
  gap: 8px !important;
}

.structItem {
  background: rgba(16, 8, 32, 0.3) !important;
  border-radius: 24px !important;
  border: 1px solid rgba(255,0,200,0.05) !important;
  padding: 12px 16px !important;
  margin-bottom: 6px !important;
  transition: all 0.25s ease !important;
  display: flex !important;
  align-items: stretch !important;
  flex-wrap: nowrap !important;
  gap: 12px !important;
}

.structItem:hover {
  background: rgba(25, 12, 50, 0.5) !important;
  border-color: rgba(255,0,200,0.12) !important;
  box-shadow: 0 4px 20px rgba(200,0,255,0.06) !important;
}

.structItem-cell {
  display: flex !important;
  align-items: center !important;
}

.structItem-cell--icon {
  flex: 0 0 48px !important;
  min-width: 48px !important;
  justify-content: center !important;
}

.structItem-cell--main {
  flex: 1 !important;
  min-width: 0 !important;
  flex-direction: column !important;
  align-items: stretch !important;
}

.structItem-cell--meta {
  flex: 0 0 100px !important;
  justify-content: center !important;
  align-items: flex-start !important;
}

.structItem-cell--latest {
  flex: 0 0 120px !important;
  justify-content: center !important;
  align-items: flex-end !important;
  text-align: right !important;
}

.structItem-cell--iconEnd {
  flex: 0 0 32px !important;
  justify-content: center !important;
}

.structItem-title {
  color: #d0b0e0 !important;
  font-weight: 500 !important;
}

.structItem-title a {
  color: #d0b0e0 !important;
}

.structItem-title a:hover {
  color: #f0c0ff !important;
  text-shadow: 0 0 30px rgba(255,0,200,0.15) !important;
}

.structItem-statuses {
  color: #9080a0 !important;
  display: flex !important;
  gap: 4px !important;
  align-items: center !important;
}

.structItem-status--locked {
  color: #ff8888 !important;
}

.structItem-status--sticky {
  color: #ffcc88 !important;
}

.structItem-minor {
  color: #807090 !important;
  font-size: 13px !important;
}

.structItem-minor a {
  color: #9080a0 !important;
}

.structItem-minor a:hover {
  color: #b0a0c0 !important;
}

.structItem-parts {
  display: flex !important;
  flex-wrap: wrap !important;
  gap: 4px !important;
  margin: 0 !important;
  padding: 0 !important;
  list-style: none !important;
}

.structItem-parts li {
  display: inline !important;
}

.structItem-latestDate {
  color: #9080a0 !important;
}

.structItem--quickCreate {
  background: rgba(16, 8, 32, 0.2) !important;
  border: 1px dashed rgba(255,0,200,0.1) !important;
  border-radius: 24px !important;
}

.structItem--quickCreate textarea {
  background: rgba(12, 6, 24, 0.6) !important;
  border: 1px solid rgba(255,0,200,0.1) !important;
  color: #c0b8d0 !important;
  border-radius: 20px !important;
  padding: 12px !important;
}

.structItem--quickCreate textarea:focus {
  border-color: rgba(255,0,200,0.3) !important;
  box-shadow: 0 0 0 4px rgba(255,0,200,0.05) !important;
}

.message {
  background: rgba(16, 8, 32, 0.35) !important;
  backdrop-filter: blur(6px) !important;
  border-radius: 28px !important;
  border: 1px solid rgba(255,0,200,0.06) !important;
  padding: 0 !important;
  margin-bottom: 20px !important;
  transition: all 0.3s ease !important;
  overflow: hidden !important;
}

.message:hover {
  background: rgba(25, 12, 50, 0.5) !important;
  border-color: rgba(255,0,200,0.15) !important;
  box-shadow: 0 8px 40px rgba(200,0,255,0.1) !important;
  transform: translateY(-2px) !important;
}

.message-inner {
  background: transparent !important;
  display: flex !important;
  flex-wrap: wrap !important;
}

.message-cell {
  background: transparent !important;
  padding: 16px !important;
}

.message-cell--user {
  background: rgba(12, 6, 24, 0.3) !important;
  border-right: 1px solid rgba(255,0,200,0.06) !important;
  border-radius: 28px 0 0 28px !important;
  min-width: 180px !important;
  flex: 0 0 180px !important;
}

.message-cell--main {
  flex: 1 !important;
  min-width: 0 !important;
  border-radius: 0 28px 28px 0 !important;
}

.message-user {
  background: transparent !important;
}

.message-avatar {
  text-align: center !important;
  margin-bottom: 8px !important;
}

.message-avatar .avatar {
  border-radius: 50% !important;
  border: 2px solid rgba(255,0,200,0.15) !important;
  transition: all 0.3s ease !important;
  box-shadow: 0 0 20px rgba(200,0,255,0.05) !important;
}

.message-avatar .avatar:hover {
  transform: scale(1.08) !important;
  border-color: rgba(255,0,200,0.4) !important;
  box-shadow: 0 0 40px rgba(200,0,255,0.2) !important;
}

.message-userDetails {
  text-align: center !important;
}

.message-name {
  font-weight: 600 !important;
  font-size: 15px !important;
}

.message-name a {
  color: #d0b0e0 !important;
}

.message-name a:hover {
  color: #f0c0ff !important;
  text-shadow: 0 0 30px rgba(255,0,200,0.2) !important;
}

.userBanner {
  background: rgba(255,0,200,0.08) !important;
  border-radius: 40px !important;
  padding: 2px 14px !important;
  font-size: 11px !important;
  color: #b0a0c0 !important;
  display: inline-block !important;
  margin-top: 4px !important;
  text-shadow: 0 0 10px rgba(200,0,255,0.05) !important;
}

.userBanner--red {
  background: rgba(200,50,50,0.15) !important;
  color: #ff8888 !important;
}

.userBanner--primary {
  background: rgba(255,0,200,0.08) !important;
  color: #b0a0c0 !important;
}

.message-userExtras {
  margin-top: 8px !important;
  font-size: 12px !important;
  color: #807090 !important;
}

.message-userExtras .pairs {
  padding: 2px 0 !important;
}

.message-userExtras .pairs dt {
  color: #706080 !important;
}

.message-userExtras .pairs dd {
  color: #a090b0 !important;
}

.message-attribution {
  background: rgba(12, 6, 24, 0.2) !important;
  padding: 8px 16px !important;
  border-bottom: 1px solid rgba(255,0,200,0.04) !important;
}

.message-attribution a {
  color: #807090 !important;
}

.message-attribution a:hover {
  color: #b0a0c0 !important;
}

.message-newIndicator {
  background: rgba(255,0,200,0.12) !important;
  color: #f080ff !important;
  border-radius: 40px !important;
  padding: 2px 12px !important;
  font-size: 11px !important;
  text-shadow: 0 0 10px rgba(255,0,200,0.2) !important;
}

.message-content {
  padding: 16px !important;
}

.message-body {
  color: #d0c8d8 !important;
  font-size: 15px !important;
  line-height: 1.7 !important;
}

.message-body .bbWrapper {
  color: #d0c8d8 !important;
}

.message-body a {
  color: #e080ff !important;
}

.message-body a:hover {
  color: #f0a0ff !important;
  text-shadow: 0 0 30px rgba(255,0,200,0.2) !important;
}

.message-body .bbMediaWrapper {
  border-radius: 20px !important;
  overflow: hidden !important;
  background: rgba(12, 6, 24, 0.6) !important;
  border: 1px solid rgba(255,0,200,0.08) !important;
}

.message-body .bbMediaWrapper iframe {
  border-radius: 20px !important;
}

.message-fields--before {
  background: rgba(12, 6, 24, 0.2) !important;
  border-radius: 20px !important;
  padding: 12px 16px !important;
  margin-bottom: 12px !important;
  border: 1px solid rgba(255,0,200,0.04) !important;
}

.message-fields--before .pairs {
  padding: 2px 0 !important;
}

.message-fields--before .pairs dt {
  color: #706080 !important;
  font-weight: 500 !important;
}

.message-fields--before .pairs dd {
  color: #b0a0c0 !important;
}

.message-signature {
  background: rgba(12, 6, 24, 0.15) !important;
  border-top: 1px solid rgba(255,0,200,0.04) !important;
  padding: 12px 16px !important;
  margin-top: 12px !important;
  border-radius: 0 0 28px 28px !important;
  font-size: 13px !important;
  color: #807090 !important;
  max-height: 100px !important;
  overflow: hidden !important;
  transition: max-height 0.3s ease !important;
}

.message-signature--expanded {
  max-height: 500px !important;
}

.message-signature .bbWrapper {
  color: #807090 !important;
}

.message-signature a {
  color: #806090 !important;
}

.message-signature a:hover {
  color: #a080b0 !important;
}

.uix_signatureExpand {
  cursor: pointer !important;
  color: #706080 !important;
  font-size: 11px !important;
  text-align: center !important;
  padding: 4px !important;
  border-radius: 40px !important;
  background: rgba(255,0,200,0.04) !important;
  margin-bottom: 6px !important;
  transition: all 0.2s !important;
}

.uix_signatureExpand:hover {
  background: rgba(255,0,200,0.08) !important;
  color: #b0a0c0 !important;
}

.actionBar {
  background: rgba(12, 6, 24, 0.15) !important;
  border-top: 1px solid rgba(255,0,200,0.04) !important;
  padding: 6px 16px !important;
  display: flex !important;
  flex-wrap: wrap !important;
  gap: 4px !important;
  border-radius: 0 0 28px 28px !important;
}

.actionBar-action {
  background: transparent !important;
  color: #807090 !important;
  padding: 4px 12px !important;
  border-radius: 40px !important;
  font-size: 13px !important;
  transition: all 0.2s !important;
  cursor: pointer !important;
}

.actionBar-action:hover {
  background: rgba(255,0,200,0.08) !important;
  color: #c0b0d0 !important;
}

.actionBar-action--reaction {
  background: rgba(255,0,200,0.04) !important;
}

.actionBar-action--reaction:hover {
  background: rgba(255,0,200,0.12) !important;
}

.actionBar-action--menuTrigger {
  color: #706080 !important;
}

.actionBar-action--menuTrigger:hover {
  background: rgba(255,0,200,0.06) !important;
}

.blockStatus {
  background: rgba(16, 8, 32, 0.5) !important;
  border-radius: 40px !important;
  border: 1px solid rgba(255,0,200,0.08) !important;
  padding: 8px 24px !important;
  color: #b0a0c0 !important;
  backdrop-filter: blur(4px) !important;
  display: inline-flex !important;
  align-items: center !important;
  gap: 8px !important;
}

.blockStatus-message {
  color: #b0a0c0 !important;
}

.blockStatus-message--locked {
  border-color: #cc6666 !important;
  color: #ff8888 !important;
  background: rgba(200,50,50,0.1) !important;
  border-radius: 40px !important;
  padding: 4px 16px !important;
}

.message-newIndicator,
.uix_newIndicator {
  background: rgba(255,0,200,0.12) !important;
  color: #f080ff !important;
  border-radius: 40px !important;
  padding: 2px 12px !important;
  font-size: 11px !important;
  font-weight: 600 !important;
  text-shadow: 0 0 10px rgba(255,0,200,0.2) !important;
}

.message--deleted {
  opacity: 0.4 !important;
  background: rgba(200,50,50,0.05) !important;
  border-color: rgba(200,50,50,0.08) !important;
}

.messageNotice--deleted {
  background: rgba(200,50,50,0.04) !important;
  border-radius: 20px !important;
  padding: 12px 16px !important;
  color: #ff8888 !important;
}

.messageNotice--deleted a {
  color: #ff8888 !important;
}

.messageNotice--deleted a:hover {
  color: #ffaaaa !important;
}

.reactionsBar {
  background: rgba(12, 6, 24, 0.15) !important;
  border-radius: 40px !important;
  padding: 4px 12px !important;
  margin: 0 16px 8px 16px !important;
  display: flex !important;
  flex-wrap: wrap !important;
  gap: 2px !important;
  min-height: 28px !important;
}

.reaction {
  background: rgba(255,0,200,0.05) !important;
  border-radius: 40px !important;
  padding: 2px 8px !important;
  transition: all 0.2s !important;
}

.reaction:hover {
  background: rgba(255,0,200,0.1) !important;
  transform: scale(1.05) !important;
}

.reaction-image--emoji {
  width: 20px !important;
  height: 20px !important;
  border-radius: 50% !important;
}

.reactionSummary {
  background: rgba(16, 8, 32, 0.3) !important;
  border-radius: 40px !important;
  padding: 2px 10px !important;
  display: inline-flex !important;
  align-items: center !important;
  gap: 2px !important;
  border: 1px solid rgba(255,0,200,0.05) !important;
}

.reactionSummary .reaction {
  padding: 1px 2px !important;
  background: transparent !important;
}

.reactionSummary .reaction:hover {
  transform: none !important;
  background: transparent !important;
}

.reactionSummary .reaction-image--emoji {
  width: 18px !important;
  height: 18px !important;
}

.pageNav {
  background: rgba(16, 8, 32, 0.4) !important;
  backdrop-filter: blur(4px) !important;
  border-radius: 40px !important;
  padding: 6px !important;
  border: 1px solid rgba(255,0,200,0.06) !important;
  display: inline-flex !important;
  flex-wrap: wrap !important;
  align-items: center !important;
  gap: 2px !important;
}

.pageNav a,
.pageNav .pageNav-page,
.pageNav-page,
.pageNav-page--current,
.pageNav-page--skip,
.pageNav-page--skipEnd,
.pageNav-page--later {
  display: inline-block !important;
  border-radius: 30px !important;
  padding: 6px 14px !important;
  min-width: 32px !important;
  height: 32px !important;
