(function() {
  const retroContainer = document.createElement('div');
  retroContainer.id = 'retro-neon-effects';
  retroContainer.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:9999;overflow:hidden;';
  document.body.prepend(retroContainer);

  function createSun() {
    const sun = document.createElement('div');
    sun.style.cssText = `
      position: absolute;
      top: 20px;
      right: 20px;
      width: 120px;
      height: 60px;
      background: radial-gradient(circle at 50% 100%, #ff00aa 0%, #ff4400 40%, #ff8800 70%, transparent 100%);
      border-radius: 120px 120px 0 0;
      opacity: 0.15;
      filter: blur(2px);
      transform-origin: bottom center;
      animation: sunPulse 6s ease-in-out infinite alternate;
      box-shadow: 0 0 80px rgba(255,0,170,0.2);
    `;
    const style = document.createElement('style');
    style.textContent = `
      @keyframes sunPulse {
        0% { transform: scale(1) rotate(0deg); opacity: 0.1; }
        100% { transform: scale(1.1) rotate(5deg); opacity: 0.2; }
      }
    `;
    document.head.appendChild(style);
    return sun;
  }

  retroContainer.appendChild(createSun());

  function createParticles() {
    const particles = [];
    for (let i = 0; i < 60; i++) {
      const p = document.createElement('div');
      const size = 1 + Math.random() * 3;
      const x = Math.random() * 100;
      const y = Math.random() * 100;
      const duration = 20 + Math.random() * 40;
      const delay = Math.random() * 30;
      const colors = ['rgba(255,0,200,0.4)', 'rgba(0,200,255,0.4)', 'rgba(255,255,0,0.3)', 'rgba(200,0,255,0.3)'];
      const color = colors[Math.floor(Math.random() * colors.length)];
      p.style.cssText = `
        position: absolute;
        left: ${x}%;
        top: ${y}%;
        width: ${size}px;
        height: ${size}px;
        background: ${color};
        border-radius: 50%;
        box-shadow: 0 0 ${size*3}px ${color};
        animation: floatParticle ${duration}s linear ${delay}s infinite alternate;
        will-change: transform;
        opacity: ${0.3 + Math.random() * 0.5};
      `;
      retroContainer.appendChild(p);
      particles.push(p);
    }
    return particles;
  }

  const particleStyle = document.createElement('style');
  particleStyle.textContent = `
    @keyframes floatParticle {
      0% { transform: translate(0, 0) scale(1); }
      25% { transform: translate(30px, -40px) scale(1.2); }
      50% { transform: translate(-20px, 30px) scale(0.8); }
      75% { transform: translate(40px, 20px) scale(1.1); }
      100% { transform: translate(-30px, -30px) scale(0.9); }
    }
  `;
  document.head.appendChild(particleStyle);

  const particles = createParticles();

  let mouseX = 0, mouseY = 0;
  document.addEventListener('mousemove', (e) => {
    mouseX = (e.clientX / window.innerWidth) * 100;
    mouseY = (e.clientY / window.innerHeight) * 100;
    particles.forEach((p, i) => {
      const dx = mouseX - parseFloat(p.style.left);
      const dy = mouseY - parseFloat(p.style.top);
      const dist = Math.sqrt(dx*dx + dy*dy);
      if (dist < 15) {
        const pushX = (dx / dist) * 8;
        const pushY = (dy / dist) * 8;
        p.style.transform = `translate(${pushX}px, ${pushY}px) scale(1.3)`;
        p.style.transition = 'transform 0.2s ease-out';
        p.style.opacity = '0.9';
      } else {
        p.style.transform = '';
        p.style.transition = 'transform 0.8s ease-out';
        p.style.opacity = '0.3';
      }
    });
  });

  document.querySelectorAll('.block, .node, .message, .structItem').forEach(el => {
